"use strict";(self.webpackChunkavstudio_docs=self.webpackChunkavstudio_docs||[]).push([[7101],{12:e=>{e.exports=JSON.parse('{"tag":{"label":"layout","permalink":"/avstudio-docs/tags/layout","allTagsPath":"/avstudio-docs/tags","count":3,"items":[{"id":"documentation/user-interface/3-7-global-containers/3-7-global-containers","title":"Global Containers Overview","description":"The Global Containers section in AVstudio lets you create persistent, reusable interface blocks that appear across multiple pages. Whether it\u2019s a navigation bar, footer, or overlay, global containers help ensure design consistency while giving you control over placement and visibility on a per-page basis.","permalink":"/avstudio-docs/documentation/user-interface/3-7-global-containers/"},{"id":"documentation/user-interface/3-5-pages/3-5-pages","title":"Pages Overview","description":"The Pages section in AVstudio is where you manage the main views of your project. From selecting layout paradigms to configuring signal-based navigation, this interface helps you create, edit, and organize the pages that structure your application.","permalink":"/avstudio-docs/documentation/user-interface/3-5-pages/"},{"id":"documentation/user-interface/3-6-subpages/3-6-subpages","title":"Subpages Overview","description":"The Subpages section in AVstudio allows you to create supporting views that complement your main pages. Subpages follow the same layout paradigms as pages and are ideal for building modular, reusable screen components within your project.","permalink":"/avstudio-docs/documentation/user-interface/3-6-subpages/"}],"unlisted":false}}')}}]);